 1	import VirtualMachineClusterInstancetypeModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineClusterInstancetypeModel';
 2	import VirtualMachineClusterPreferenceModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineClusterPreferenceModel';
 3	import VirtualMachineInstancetypeModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineInstancetypeModel';
 4	import VirtualMachinePreferenceModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachinePreferenceModel';
 5	import {
 6	  K8sVerb,
 7	  SetFeatureFlag,
 8	  useAccessReview,
 9	  useActiveNamespace,
10	} from '@openshift-console/dynamic-plugin-sdk';
11	
12	import { FLAG_KUBEVIRT_INSTANCETYPES, FLAG_KUBEVIRT_PREFERENCES } from './consts';
13	
14	const useEnableKubevirtMenuFlags = (setFeatureFlag: SetFeatureFlag) => {
15	  const [namespace] = useActiveNamespace();
16	
17	  const [canShowClusterInstancetypes] = useAccessReview({
18	    group: VirtualMachineClusterInstancetypeModel.apiGroup,
19	    resource: VirtualMachineClusterInstancetypeModel.plural,
20	    verb: 'list' as K8sVerb,
21	  });
22	
23	  const [canShowInstancetypes] = useAccessReview({
24	    group: VirtualMachineInstancetypeModel.apiGroup,
25	    namespace,
26	    resource: VirtualMachineInstancetypeModel.plural,
27	    verb: 'list' as K8sVerb,
28	  });
29	  const [canShowClusterPreferences] = useAccessReview({
30	    group: VirtualMachineClusterPreferenceModel.apiGroup,
31	    namespace,
32	    resource: VirtualMachineClusterPreferenceModel.plural,
33	    verb: 'list' as K8sVerb,
34	  });
35	
36	  const [canShowPreferences] = useAccessReview({
37	    group: VirtualMachinePreferenceModel.apiGroup,
38	    namespace,
39	    resource: VirtualMachinePreferenceModel.plural,
40	    verb: 'list' as K8sVerb,
41	  });
42	
43	  setFeatureFlag(FLAG_KUBEVIRT_PREFERENCES, canShowPreferences || canShowClusterPreferences);
44	  setFeatureFlag(FLAG_KUBEVIRT_INSTANCETYPES, canShowInstancetypes || canShowClusterInstancetypes);
45	};
46	
47	export default useEnableKubevirtMenuFlags;

